import{z as t}from"zod";export const StoryDomainSchema=t.enum(["character","world","location","plot_thread","timeline","theme"]),StoryCategorySchema=t.enum(["identity","personality","appearance","ability","background","relation","rule","faction","history","system","geography","venue","region","foreshadow","task","mystery","causality","event","milestone","season","motif","symbol","conflict"]),FactTierSchema=t.enum(["pinned","ambient"]),FactStatusSchema=t.enum(["active","archived","voided"]),StoryFactSchema=t.object({id:t.string(),domain:StoryDomainSchema,category:StoryCategorySchema,label:t.string(),content:t.string(),weight:t.number().min(0).max(100),certainty:t.number().min(0).max(1),tier:FactTierSchema.default("ambient"),status:FactStatusSchema.default("active"),triggers:t.array(t.string()).default([]),emotionalWeight:t.number().min(-1).max(1).default(0),narrativeRelevance:t.number().min(0).max(1).default(.5),chapterOrigin:t.number().int().min(0).default(0),derivedFrom:t.array(t.string()).optional(),createdAt:t.string(),updatedAt:t.string(),accessCount:t.number().int().min(0).default(0),lastAccessAt:t.string().optional()});
